DetectionRule.DetectionLogic:
let UACBypassPaths = dynamic([ "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\EnableLUA", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\ConsentPromptBehaviorAdmin", "HKLM\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System\\PromptOnSecureDesktop", "C:\\Windows\\System32\\sysprep\\sysprep.exe", "C:\\Windows\\System32\\cliconfg.exe", "C:\\Windows\\System32\\computerdefaults.exe", "C:\\Windows\\System32\\oobe\\setupsqm.exe" ]);
let SuspiciousDLLs = dynamic([ "cryptbase.dll", "wtsapi32.dll", "appinfo.dll", "hc.dll", "igfxCU.dll", "fodhelper.dll", "mavinject.dll", "cmstp.exe", "regsvr32.exe" ]);
// Detect UAC registry modifications DeviceRegistryEvents | where Timestamp > ago(4h) | where RegistryKey has_any (UACBypassPaths) and ActionType in~ ("RegistryValueSet", "RegistryKeyCreated") and InitiatingProcessFileName !in~ ("System", "svchost.exe", "services.exe", "msiexec.exe") | extend RegistryValue = tostring(RegistryValueName) | extend ValueData = tostring(RegistryValue) | where ValueData in~ ("0", "disabled", "false") // Disabling UAC or RegistryValue == "ConsentPromptBehaviorAdmin" and ValueData == "0" or RegistryValue == "PromptOnSecureDesktop" and ValueData == "0" | summarize RegistryModifications = count(), ModifiedValues = makeset(RegistryValue) by DeviceId, RegistryKey, AccountName, ProcessName
// Also detect auto-elevating COM object abuse union ( DeviceProcessEvents | where Timestamp > ago(4h) | where FileName in~ ("fodhelper.exe", "computerdefaults.exe", "cliconfg.exe", "eventvwr.exe") and InitiatingProcessFileName !in~ ("explorer.exe", "System", "taskhostw.exe") | extend COMAbuse = case( FileName in~ ("fodhelper.exe", "computerdefaults.exe", "cliconfg.exe"), "Auto-Elevating COM", "Other UAC Bypass" ) | where COMAbuse == "Auto-Elevating COM" | summarize COMAbuses = count() by DeviceId, FileName, AccountName )
// Also detect DLL hijacking for UAC bypass union ( DeviceProcessEvents | where Timestamp > ago(4h) | where FileName in~ ("fodhelper.exe", "computerdefaults.exe", "eventvwr.exe") and InitiatingProcessFileName !in~ ("explorer.exe", "System") | where ProcessCommandLine has_any (SuspiciousDLLs) or ProcessCommandLine has "HKCU\\Software\\Classes" // Registry-based DLL hijacking | summarize HijackAttempts = count() by DeviceId, FileName, AccountName ) | extend FinalRisk = case( RegistryModifications >= 2 or COMAbuses >= 2 or HijackAttempts >= 2, "High", RegistryModifications == 1 or COMAbuses == 1 or HijackAttempts == 1, "Medium", "Low" ) | where FinalRisk in~ ("High", "Medium") | project-reorder Timestamp, DeviceId, FinalRisk, RegistryModifications, COMAbuses, HijackAttempts

let TokenManipulationAPIs = dynamic([ "OpenProcessToken", "DuplicateTokenEx", "ImpersonateLoggedOnUser", "SetThreadToken", "CreateProcessWithTokenW", "CreateProcessAsUser", "AdjustTokenPrivileges", "SeDebugPrivilege", "SeImpersonatePrivilege", "SeAssignPrimaryPrivilege", "SeTcbPrivilege" ]);
let SuspiciousTokenTools = dynamic([ "mimikatz", "incognito", "metasploit", "cobaltstrike", "powershell", "rubeus", "kekeo", "safetykatz" ]);
// Detect token manipulation API calls DeviceApiCalls | where Timestamp > ago(2h) | where ApiName in~ (TokenManipulationAPIs) and InitiatingProcessFileName !in~ ("lsass.exe", "svchost.exe", "services.exe", "System") | extend TokenAPIRisk = case( ApiName in~ ("CreateProcessWithTokenW", "ImpersonateLoggedOnUser", "DuplicateTokenEx"), "Critical", ApiName in~ ("AdjustTokenPrivileges", "OpenProcessToken"), "High", "Medium" ) | where TokenAPIRisk in~ ("Critical", "High") | summarize TokenAPICalls = count(), RiskLevel = max(TokenAPIRisk), APIs = makeset(ApiName) by DeviceId, InitiatingProcessFileName, AccountName | where TokenAPICalls >= 2
// Also detect suspicious tools known for token manipulation union ( DeviceProcessEvents | where Timestamp > ago(2h) | where FileName in~ (SuspiciousTokenTools) or ProcessCommandLine has_any (TokenManipulationAPIs) | where InitiatingProcessFileName !in~ ("System", "svchost.exe", "services.exe") | extend ToolRisk = case( FileName in~ ("mimikatz", "cobaltstrike", "rubeus"), "Critical", FileName == "incognito", "High", "Medium" ) | summarize ToolRuns = count(), RiskLevel = max(ToolRisk), Commands = makeset(ProcessCommandLine) by DeviceId, FileName, AccountName ) | extend FinalRisk = case( RiskLevel == "Critical" or ToolRuns >= 3, "Critical", RiskLevel == "High" or TokenAPICalls >= 5 or ToolRuns >= 2, "High", "Medium" ) | where FinalRisk in~ ("Critical", "High") | project-reorder Timestamp, DeviceId, FinalRisk, TokenAPICalls, ToolRuns, AccountName

let KnownVulnerableDrivers = dynamic([ "gdrv.sys", "cvexpress.sys", "nvidia_display.sys", "vboxdrv.sys", "vmci.sys", "prnport01.dll", "eamonm.sys", "rc.sys", "pcalua.exe", "pcwum.sys", "ibmapp.sys", "gmer6.sys", "radhslib.sys", "enespi.sys", "lgnwifi.sys" ]);
let SuspiciousDriverPaths = dynamic([ "\\Users\\", "\\Temp\\", "\\AppData\\", "\\Windows\\Temp\\", "\\ProgramData\\" ]);
// Detect driver installation from suspicious locations DeviceDriverEvents | where Timestamp > ago(4h) | where DriverName in~ (KnownVulnerableDrivers) or DriverPath has_any (SuspiciousDriverPaths) or DriverSigned == false | extend DriverRisk = case( DriverName in~ (KnownVulnerableDrivers), "Critical", DriverPath has_any (SuspiciousDriverPaths), "High", DriverSigned == false, "Medium", "Low" ) | where DriverRisk in~ ("Critical", "High") | summarize DriverInstalls = count(), RiskLevel = max(DriverRisk), Drivers = makeset(DriverName) by DeviceId, DriverPath, AccountName, InitiatingProcessFileName
// Also detect suspicious service creation with driver paths union ( DeviceRegistryEvents | where Timestamp > ago(4h) | where RegistryKey has "SYSTEM\\CurrentControlSet\\Services" and RegistryKey !endswith "Enum" and RegistryValue contains ".sys" and (RegistryValue has_any (SuspiciousDriverPaths) or RegistryValue has_any (KnownVulnerableDrivers)) and ActionType in~ ("RegistryKeyCreated", "RegistryValueSet") and InitiatingProcessFileName !in~ ("System", "services.exe", "msiexec.exe") | extend ServiceName = tostring(split(RegistryKey, '\\')[-1]) | extend DriverPath = RegistryValue | summarize DriverServices = count(), UniqueDrivers = dcount(ServiceName) by DeviceId, InitiatingProcessFileName, AccountName, DriverPath ) | extend FinalRisk = case( RiskLevel == "Critical" or DriverInstalls >= 2 or DriverServices >= 2, "Critical", RiskLevel == "High" or DriverInstalls == 1 or DriverServices == 1, "High", "Medium" ) | where FinalRisk in~ ("Critical", "High") | project-reorder Timestamp, DeviceId, FinalRisk, DriverInstalls, DriverServices, AccountName
